import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import eventApi from "../../api/eventApi";
import "./event.css";

export default function EventList() {
  const navigate = useNavigate();
  const [events, setEvents] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [deleteDialog, setDeleteDialog] = useState({ open: false, eventId: null, eventName: "" });
  const [filter, setFilter] = useState("all"); // all, holiday, weather, flood, special

  useEffect(() => {
    fetchEvents();
  }, []);

  const fetchEvents = async () => {
    try {
      setLoading(true);
      const data = await eventApi.getAllEvents();
      setEvents(data);
      setError(null);
    } catch (err) {
      setError(err.response?.data?.message || "Failed to fetch events");
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async () => {
    if (!deleteDialog.eventId) return;

    try {
      await eventApi.deleteEvent(deleteDialog.eventId);
      setEvents(events.filter(e => e._id !== deleteDialog.eventId));
      setDeleteDialog({ open: false, eventId: null, eventName: "" });
    } catch (err) {
      alert(err.response?.data?.message || "Failed to delete event");
    }
  };

  const filteredEvents = filter === "all" 
    ? events 
    : events.filter(e => e.type === filter);

  const getEventTypeColor = (type) => {
    switch (type) {
      case "holiday": return "#4CAF50";
      case "weather": return "#2196f3";
      case "flood": return "#00bcd4";
      case "special": return "#9c27b0";
      default: return "#ff9800";
    }
  };

  const getEventTypeLabel = (type) => {
    return type.charAt(0).toUpperCase() + type.slice(1);
  };

  const formatDate = (dateString) => {
    const date = new Date(dateString);
    return date.toLocaleDateString("en-US", {
      year: "numeric",
      month: "short",
      day: "numeric"
    });
  };

  if (loading) {
    return (
      <div className="page">
        <div style={{ textAlign: "center", padding: "60px 20px", color: "var(--text-muted)" }}>
          Loading events...
        </div>
      </div>
    );
  }

  return (
    <div className="page">
      {/* Header */}
      <div className="pageHead">
        <div className="pageHeadLeft">
          <h1 className="h1">Event Management</h1>
          <p className="pageSub">Manage shop closures, holidays, and special events</p>
        </div>
        <button 
          className="btn btnPrimary"
          onClick={() => navigate("/events/add")}
        >
          ➕ Add Event
        </button>
      </div>

      {/* Error Alert */}
      {error && (
        <div style={{
          padding: "16px",
          backgroundColor: "#ffebee",
          color: "#c62828",
          borderRadius: "10px",
          marginBottom: "24px",
          fontSize: "14px"
        }}>
          {error}
        </div>
      )}

      {/* Filter Buttons */}
      <div className="event-filters" style={{
        display: "flex",
        gap: "12px",
        marginBottom: "24px",
        flexWrap: "wrap"
      }}>
        {["all", "holiday", "weather", "flood", "special"].map(type => (
          <button
            key={type}
            className={`btn ${filter === type ? "btnPrimary" : "btnOutline"}`}
            onClick={() => setFilter(type)}
            style={{
              fontSize: "13px",
              fontWeight: "600"
            }}
          >
            {type === "all" ? "All Events" : getEventTypeLabel(type)}
          </button>
        ))}
      </div>

      {/* Events Grid */}
      {filteredEvents.length === 0 ? (
        <div className="card" style={{
          padding: "48px 24px",
          textAlign: "center",
          color: "var(--text-muted)"
        }}>
          <p style={{ fontSize: "16px", margin: 0 }}>
            {events.length === 0 ? "No events yet" : `No ${filter === "all" ? "" : filter} events`}
          </p>
        </div>
      ) : (
        <div style={{
          display: "grid",
          gridTemplateColumns: "repeat(auto-fill, minmax(350px, 1fr))",
          gap: "24px"
        }}>
          {filteredEvents.map(event => (
            <div key={event._id} className="card event-card" style={{
              display: "flex",
              flexDirection: "column"
            }}>
              {/* Header */}
              <div style={{
                display: "flex",
                alignItems: "flex-start",
                gap: "12px",
                marginBottom: "16px",
                paddingBottom: "16px",
                borderBottom: "1px solid var(--border)"
              }}>
                <div style={{
                  width: "4px",
                  height: "40px",
                  backgroundColor: event.color || getEventTypeColor(event.type),
                  borderRadius: "2px"
                }} />
                <div style={{ flex: 1 }}>
                  <h3 className="h3" style={{ margin: "0 0 6px 0" }}>
                    {event.name}
                  </h3>
                  <div style={{ display: "flex", gap: "8px", alignItems: "center" }}>
                    <span className="badge" style={{
                      backgroundColor: getEventTypeColor(event.type) + "1a",
                      color: getEventTypeColor(event.type),
                      fontSize: "11px",
                      padding: "4px 10px"
                    }}>
                      {getEventTypeLabel(event.type)}
                    </span>
                    {event.isShopClosed && (
                      <span className="badge" style={{
                        backgroundColor: "#ffebee",
                        color: "#c62828",
                        fontSize: "11px",
                        padding: "4px 10px"
                      }}>
                        Shop Closed
                      </span>
                    )}
                  </div>
                </div>
              </div>

              {/* Dates */}
              <div style={{
                display: "grid",
                gridTemplateColumns: "1fr 1fr",
                gap: "16px",
                marginBottom: "16px",
                fontSize: "13px"
              }}>
                <div>
                  <div style={{ color: "var(--text-muted)", marginBottom: "4px", fontWeight: "600" }}>
                    Start Date
                  </div>
                  <div style={{ color: "var(--text)", fontWeight: "600" }}>
                    {formatDate(event.startDate)}
                  </div>
                </div>
                <div>
                  <div style={{ color: "var(--text-muted)", marginBottom: "4px", fontWeight: "600" }}>
                    End Date
                  </div>
                  <div style={{ color: "var(--text)", fontWeight: "600" }}>
                    {formatDate(event.endDate)}
                  </div>
                </div>
              </div>

              {/* Description */}
              {event.description && (
                <div style={{
                  marginBottom: "16px",
                  padding: "12px",
                  backgroundColor: "var(--bg-hover)",
                  borderRadius: "8px",
                  fontSize: "13px",
                  color: "var(--text-muted)",
                  lineHeight: "1.5"
                }}>
                  {event.description}
                </div>
              )}

              {/* Created By */}
              <div style={{
                fontSize: "12px",
                color: "var(--text-muted)",
                marginBottom: "16px"
              }}>
                Created by <strong>{event.createdBy?.name}</strong>
              </div>

              {/* Actions */}
              <div style={{
                display: "flex",
                gap: "12px",
                marginTop: "auto",
                paddingTop: "16px",
                borderTop: "1px solid var(--border)"
              }}>
                <button
                  className="btn btnPrimary"
                  onClick={() => navigate(`/events/edit/${event._id}`)}
                  style={{ flex: 1, fontSize: "13px" }}
                >
                  Edit
                </button>
                <button
                  className="btn"
                  onClick={() => setDeleteDialog({
                    open: true,
                    eventId: event._id,
                    eventName: event.name
                  })}
                  style={{
                    flex: 1,
                    fontSize: "13px",
                    color: "#f44336",
                    borderColor: "#f44336"
                  }}
                >
                  Delete
                </button>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Delete Confirmation Dialog */}
      {deleteDialog.open && (
        <div style={{
          position: "fixed",
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          backgroundColor: "rgba(0,0,0,0.5)",
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          zIndex: 999
        }}>
          <div className="card" style={{
            width: "100%",
            maxWidth: "400px",
            padding: "24px"
          }}>
            <h2 className="h2" style={{ marginBottom: "12px" }}>Delete Event?</h2>
            <p style={{ color: "var(--text-muted)", marginBottom: "24px" }}>
              Are you sure you want to delete "<strong>{deleteDialog.eventName}</strong>"? This action cannot be undone.
            </p>
            <div style={{ display: "flex", gap: "12px" }}>
              <button
                className="btn"
                onClick={() => setDeleteDialog({ open: false, eventId: null, eventName: "" })}
                style={{ flex: 1 }}
              >
                Cancel
              </button>
              <button
                className="btn btnDanger"
                onClick={handleDelete}
                style={{ flex: 1 }}
              >
                Delete
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
